-- CBSE PUC basic puzzles (100), funbrain / puzzles. Pack: cbse_puzzles_puc100_basic.
-- Idempotent: delete this pack in puzzles, then insert.

BEGIN;

DELETE FROM public.play_questions
WHERE domain = 'funbrain'
  AND category = 'puzzles'
  AND (content->>'pack') = 'cbse_puzzles_puc100_basic';


COMMIT;
