INSERT INTO public.play_questions (domain, category, content, options, correct_answer_index, explanation)
VALUES
  ('funbrain', 'puzzles', '{"text": "What is the next number in the sequence: 2, 6, 12, 20, 30, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["36", "40", "48", "42"]'::jsonb, 3, 'Differences increase by even steps: +4,+6,+8,+10; next +12 → 42.'),
  ('funbrain', 'puzzles', '{"text": "What comes next: 1, 1, 2, 3, 5, 8, 13, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["34", "18", "21", "20"]'::jsonb, 2, 'Fibonacci: each term is sum of previous two (8+13=21).'),
  ('funbrain', 'puzzles', '{"text": "What is the next number: 1, 4, 9, 16, 25, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["30", "32", "49", "36"]'::jsonb, 3, 'Perfect squares: 6² = 36.'),
  ('funbrain', 'puzzles', '{"text": "Find the missing number: 3, 9, 27, 81, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["162", "324", "243", "729"]'::jsonb, 2, 'Multiply by 3 each time: 81×3 = 243.'),
  ('funbrain', 'puzzles', '{"text": "What comes next: 2, 3, 5, 7, 11, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["17", "9", "15", "13"]'::jsonb, 3, 'Consecutive primes; next after 11 is 13.'),
  ('funbrain', 'puzzles', '{"text": "What is the next number: 8, 27, 64, 125, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["343", "256", "200", "216"]'::jsonb, 3, 'Cubes: 2³…5³; next 6³ = 216.'),
  ('funbrain', 'puzzles', '{"text": "Find the next number: 10, 9, 7, 4, 0, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["1", "−4", "−5", "5"]'::jsonb, 2, 'Subtract 1,2,3,4… next subtract 5 from 0.'),
  ('funbrain', 'puzzles', '{"text": "What is the next number: 2, 4, 8, 16, 32, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["128", "96", "64", "48"]'::jsonb, 2, 'Powers of 2; double 32.'),
  ('funbrain', 'puzzles', '{"text": "Find the missing number: 121, 144, 169, 196, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["225", "214", "210", "200"]'::jsonb, 0, '11²…14²; next 15² = 225.'),
  ('funbrain', 'puzzles', '{"text": "What is the next number: 100, 96, 91, 85, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["80", "72", "78", "77"]'::jsonb, 2, 'Decreases by 4,5,6… next −7: 85−7 = 78.'),
  ('funbrain', 'puzzles', '{"text": "I am an odd number. Take away one letter from my name and I become even. What number am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Nine", "Five", "Eleven", "Seven"]'::jsonb, 3, 'Remove S from SEVEN → EVEN.'),
  ('funbrain', 'puzzles', '{"text": "Which three positive numbers give the same result whether added or multiplied?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["0, 1, 2", "2, 2, 2", "1, 1, 1", "1, 2, and 3"]'::jsonb, 3, '1+2+3 = 6 and 1×2×3 = 6.'),
  ('funbrain', 'puzzles', '{"text": "A bat and a ball cost ₹110 total. The bat costs ₹100 more than the ball. How much is the ball?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["₹15", "₹10", "₹5", "₹55"]'::jsonb, 2, 'x + (x+100) = 110 → x = 5.'),
  ('funbrain', 'puzzles', '{"text": "If 5 machines make 5 widgets in 5 minutes, how long for 100 machines to make 100 widgets?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["20 minutes", "50 minutes", "100 minutes", "5 minutes"]'::jsonb, 3, 'Each machine makes one widget in 5 min; parallel work still 5 min.'),
  ('funbrain', 'puzzles', '{"text": "Lily pads double in area daily; full pond on day 48. When was it half covered?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["47 days", "24 days", "48 days", "46 days"]'::jsonb, 0, 'Half a day before full = one doubling step earlier.'),
  ('funbrain', 'puzzles', '{"text": "A farmer has 17 sheep. All but 9 run away. How many are left?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["0", "9", "17", "8"]'::jsonb, 1, 'All but nine means nine remain.'),
  ('funbrain', 'puzzles', '{"text": "How many times can you subtract 10 from 100?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Ten times", "Nine times", "Five times", "Only once"]'::jsonb, 3, 'After first subtraction you subtract from 90, not 100.'),
  ('funbrain', 'puzzles', '{"text": "Divide 30 by a half and add 10. What is the result?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["25", "35", "70", "40"]'::jsonb, 2, '30 ÷ 0.5 = 60; 60 + 10 = 70.'),
  ('funbrain', 'puzzles', '{"text": "What is \"half of two plus two\"?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["1", "2", "4", "3"]'::jsonb, 3, 'Half of two is 1, then 1 + 2 = 3 (order of wording).'),
  ('funbrain', 'puzzles', '{"text": "If a dozen eggs cost ₹12, how many eggs can you buy for ₹100?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["100 eggs", "120", "8 dozen", "50"]'::jsonb, 0, '₹1 per egg → 100 eggs.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: O, T, T, F, F, S, S, E, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["N", "O", "I", "T"]'::jsonb, 0, 'First letters of One, Two, … Eight; next Nine → N.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: J, F, M, A, M, J, J, A, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["S", "D", "N", "O"]'::jsonb, 0, 'Months January…August; next September → S.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: M, V, E, M, J, S, U, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["P", "U", "V", "N"]'::jsonb, 3, 'Planets Mercury…Uranus; next Neptune → N.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: S, M, T, W, T, F, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["T", "W", "S", "M"]'::jsonb, 2, 'Days Sun…Fri; next Saturday → S.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: A, C, F, J, O, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["T", "U", "V", "X"]'::jsonb, 1, 'Skip 1,2,3,4,5 letters between terms.'),
  ('funbrain', 'puzzles', '{"text": "What letter comes next: Z, Y, X, W, V, ?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["T", "S", "U", "W"]'::jsonb, 2, 'Alphabet backwards.'),
  ('funbrain', 'puzzles', '{"text": "Forward I am heavy, backward I am not. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Stone", "Lead", "A pound", "A ton"]'::jsonb, 3, 'TON reversed is NOT.'),
  ('funbrain', 'puzzles', '{"text": "What word is spelled incorrectly in every dictionary?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Wrongly", "Mistake", "Incorrectly", "Error"]'::jsonb, 2, 'The word itself is the answer.'),
  ('funbrain', 'puzzles', '{"text": "I have cities but no houses, mountains but no trees, water but no fish. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["GPS", "A globe", "A map", "A painting"]'::jsonb, 2, 'Symbolic geography only.'),
  ('funbrain', 'puzzles', '{"text": "The more you take, the more you leave behind. What are they?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Footsteps", "Shadows", "Money", "Breath"]'::jsonb, 0, 'Walking leaves a trail.'),
  ('funbrain', 'puzzles', '{"text": "A plane crashes on the US–Canada border. Where are survivors buried?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["USA", "Nowhere", "The border line", "Canada"]'::jsonb, 1, 'Survivors are not buried.'),
  ('funbrain', 'puzzles', '{"text": "A rooster lays an egg on a barn roof. Which way does the egg roll?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Nowhere / It does not", "Down the slope", "West", "East"]'::jsonb, 0, 'Roosters do not lay eggs.'),
  ('funbrain', 'puzzles', '{"text": "How much dirt is inside a 3 ft deep, 3 ft wide hole?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["None", "27 cubic feet", "9 cubic feet", "3 pounds"]'::jsonb, 0, 'A hole is empty space.'),
  ('funbrain', 'puzzles', '{"text": "Electric train north 100 mph; wind west 10 mph. Which way does the smoke blow?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["West", "Southwest", "Nowhere / No smoke", "North"]'::jsonb, 2, 'Electric trains produce no smoke.'),
  ('funbrain', 'puzzles', '{"text": "What weighs more: a pound of feathers or a pound of bricks?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Feathers", "Bricks", "They weigh the same", "Cannot tell"]'::jsonb, 2, 'Both are one pound.'),
  ('funbrain', 'puzzles', '{"text": "A house has all four walls facing South. A bear passes the window. What color is the bear?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Brown", "Black", "Gray", "White"]'::jsonb, 3, 'Only at North Pole can all walls face south; polar bear.'),
  ('funbrain', 'puzzles', '{"text": "Can a man marry his widow''s sister?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Yes", "No", "Sometimes", "Only abroad"]'::jsonb, 1, 'A widow implies the man is dead.'),
  ('funbrain', 'puzzles', '{"text": "You overtake the runner in second place in a marathon. What place are you in?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Second place", "Third place", "First place", "Last place"]'::jsonb, 0, 'You took their spot.'),
  ('funbrain', 'puzzles', '{"text": "You overtake the last person in a race. What place are you in?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Last place", "Impossible", "First place", "Second to last"]'::jsonb, 1, 'You cannot be behind the last person and overtake them.'),
  ('funbrain', 'puzzles', '{"text": "Two coins total 30 cents. One is not a nickel. What are the coins?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Two nickels", "Two dimes", "Three dimes", "A quarter and a nickel"]'::jsonb, 3, 'The quarter is not a nickel; the other coin is.'),
  ('funbrain', 'puzzles', '{"text": "Father 36, son 11. In how many years is father twice as old as son?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["25 years", "10 years", "14 years", "7 years"]'::jsonb, 2, '36+14=50, 11+14=25; 50=2×25.'),
  ('funbrain', 'puzzles', '{"text": "Snail in 20 ft well: climbs 5 ft by day, slides 4 ft by night. Days to exit?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["4 days", "20 days", "16 days", "15 days"]'::jsonb, 2, 'Net +1 ft/day until final climb clears top on day 16.'),
  ('funbrain', 'puzzles', '{"text": "Grandfather clock: 2 seconds to strike 3 o''clock. Time to strike 6?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["3 seconds", "4 seconds", "6 seconds", "5 seconds"]'::jsonb, 3, '3 strikes = 2 gaps → 1 s per gap; 6 strikes = 5 gaps.'),
  ('funbrain', 'puzzles', '{"text": "Day before yesterday I was 21; next year I will be 24. When is my birthday?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["March 1st", "December 31st", "June 15th", "January 1st"]'::jsonb, 1, 'Statement on Jan 1: Dec 30 was 21; Dec 31 birthday; next year age 24.'),
  ('funbrain', 'puzzles', '{"text": "Two monkeys type two pages in two minutes. Monkeys to type 18 pages in 18 minutes?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["18 monkeys", "Two monkeys", "6 monkeys", "9 monkeys"]'::jsonb, 1, 'Rate 1 page per monkey per 2 min; same two suffice.'),
  ('funbrain', 'puzzles', '{"text": "Trains 60 mph and 40 mph toward each other from stations 100 mi apart. Time until they meet?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["30 minutes", "1 hour", "100 minutes", "2 hours"]'::jsonb, 1, 'Closing speed 100 mph covers 100 mi in 1 h.'),
  ('funbrain', 'puzzles', '{"text": "Add 5 to 9 and get 2. How is this correct?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Roman numerals", "Mod 12 arithmetic only", "Wrong math", "Time on a clock"]'::jsonb, 3, '9:00 + 5 hours = 2:00.'),
  ('funbrain', 'puzzles', '{"text": "Mary''s father has five daughters: Nana, Nene, Nini, Nono. Fifth daughter''s name?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Nono", "Nini", "Mary", "Nana"]'::jsonb, 2, 'Stated in the first words.'),
  ('funbrain', 'puzzles', '{"text": "How many months have 28 days?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Eleven months", "All 12 months", "One month", "February only"]'::jsonb, 1, 'Every month has at least 28 days.'),
  ('funbrain', 'puzzles', '{"text": "Two parents, six sons, each son has one sister. Total people?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["8", "10", "14", "9 people"]'::jsonb, 3, '2 parents + 6 sons + 1 shared sister.'),
  ('funbrain', 'puzzles', '{"text": "How many squares on a standard 8×8 chessboard?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["100", "64", "128", "204"]'::jsonb, 3, 'Sum of k² for k=1..8 = 204.'),
  ('funbrain', 'puzzles', '{"text": "How many times does digit ''9'' appear from 1 to 100?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["19", "11", "18", "20 times"]'::jsonb, 3, '9,19,…,89 and 90–99 (99 counts twice).'),
  ('funbrain', 'puzzles', '{"text": "3 apples on a table; you take away 2. How many do you have?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["2 apples", "0", "3", "1"]'::jsonb, 0, 'You possess the two you took.'),
  ('funbrain', 'puzzles', '{"text": "6 eggs: broke 2, cooked 2, ate 2. How many left?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["4 eggs", "2", "6", "0"]'::jsonb, 0, 'Same two eggs in all three actions.'),
  ('funbrain', 'puzzles', '{"text": "10 black and 10 white socks in dark drawer. Minimum to guarantee a matching pair?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["20 socks", "3 socks", "4 socks", "2 socks"]'::jsonb, 1, 'Third must match one of first two colors.'),
  ('funbrain', 'puzzles', '{"text": "How many times does digit ''1'' appear from 1 to 10?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Twice", "Nine times", "Once", "Ten times"]'::jsonb, 0, 'In 1 and in 10.'),
  ('funbrain', 'puzzles', '{"text": "Multiply all digits on a standard phone keypad (0–9). Result?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["0", "3628800", "45", "10"]'::jsonb, 0, 'Zero is on the pad; product is 0.'),
  ('funbrain', 'puzzles', '{"text": "How many corners does a standard 3D cube have?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["6", "12", "4", "8 corners"]'::jsonb, 3, '4 top + 4 bottom vertices.'),
  ('funbrain', 'puzzles', '{"text": "How many edges does a solid sphere have?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Infinite", "360", "1", "Zero"]'::jsonb, 3, 'Smooth surface; no straight edges.'),
  ('funbrain', 'puzzles', '{"text": "Interior degrees in a full circle?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["100 degrees", "360 degrees", "90 degrees", "180 degrees"]'::jsonb, 1, 'One full rotation.'),
  ('funbrain', 'puzzles', '{"text": "I am tall when young, short when old. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A tree", "A person", "A building", "A candle (or a pencil)"]'::jsonb, 3, 'Burns or is sharpened away.'),
  ('funbrain', 'puzzles', '{"text": "What must be broken before you can use it?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A rule", "Glass", "An egg", "A lock"]'::jsonb, 2, 'Crack the shell to cook or eat.'),
  ('funbrain', 'puzzles', '{"text": "Full of keys but opens no doors. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A keyboard", "A ring", "A piano", "A map"]'::jsonb, 2, 'Musical keys.'),
  ('funbrain', 'puzzles', '{"text": "You can catch it but never throw it. What is it?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A cold", "A ball", "Wind", "A fish"]'::jsonb, 0, 'Illness wordplay.'),
  ('funbrain', 'puzzles', '{"text": "What has one eye but cannot see?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A cyclops", "A needle", "A potato", "A storm"]'::jsonb, 1, 'The thread hole is the eye.'),
  ('funbrain', 'puzzles', '{"text": "What belongs to you but others use more than you?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Your time", "Your money", "Your name", "Your phone"]'::jsonb, 2, 'Others call you by it.'),
  ('funbrain', 'puzzles', '{"text": "What only goes up and never comes down?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Temperature", "A balloon", "Your age", "Stairs"]'::jsonb, 2, 'Time moves forward.'),
  ('funbrain', 'puzzles', '{"text": "What gets bigger the more you remove from it?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A rumor", "A debt", "A shadow", "A hole"]'::jsonb, 3, 'Digging removes more material.'),
  ('funbrain', 'puzzles', '{"text": "Has pages and a cover but never speaks. What is it?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A book", "A PDF", "A magazine", "A diary"]'::jsonb, 0, 'Silent reading.'),
  ('funbrain', 'puzzles', '{"text": "Travels the world but stays in a corner. What is it?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A tourist", "A postage stamp", "Wi‑Fi", "A coin"]'::jsonb, 1, 'Corner of the envelope.'),
  ('funbrain', 'puzzles', '{"text": "What has a head and a tail but no body?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A comet", "A snake", "A tadpole", "A coin"]'::jsonb, 3, 'Heads and tails sides.'),
  ('funbrain', 'puzzles', '{"text": "I have branches but no fruit, trunk, or leaves. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A tree", "Git", "A bank", "A river delta"]'::jsonb, 2, 'Branch offices.'),
  ('funbrain', 'puzzles', '{"text": "What gets wetter as it dries?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Paint", "Hair", "A towel", "A sponge"]'::jsonb, 2, 'Absorbs water from you.'),
  ('funbrain', 'puzzles', '{"text": "What has hands but cannot clap?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A statue", "A clock", "Gloves", "A robot"]'::jsonb, 1, 'Hour and minute hands.'),
  ('funbrain', 'puzzles', '{"text": "No life but can die. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Fire", "A battery", "A star", "Software"]'::jsonb, 1, 'Goes dead when discharged.'),
  ('funbrain', 'puzzles', '{"text": "What breaks without falling, and what falls without breaking?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Ice and snow", "Heart and tears", "Glass and rain", "Day breaks, and night falls."]'::jsonb, 3, 'English idioms.'),
  ('funbrain', 'puzzles', '{"text": "Yellow hat dropped in the Red Sea. What happens?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Red", "It floats forever", "Yellow", "Wet"]'::jsonb, 3, 'Name of sea does not dye it; it gets wet.'),
  ('funbrain', 'puzzles', '{"text": "Goes up and down without moving location?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["An elevator", "Temperature", "Stock price", "A staircase"]'::jsonb, 3, 'Fixed structure.'),
  ('funbrain', 'puzzles', '{"text": "What is at the end of every rainbow?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["The letter ''W''", "Sky", "Gold", "Pot"]'::jsonb, 0, 'End of the word rainbow.'),
  ('funbrain', 'puzzles', '{"text": "Turned on my side I am infinite; cut in half I am nothing. What am I?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A Möbius strip", "The number 8", "A circle", "The letter O"]'::jsonb, 1, 'Sideways ∞; halved looks like 0 0.'),
  ('funbrain', 'puzzles', '{"text": "Three matches, no breaking: how make four?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Light four fires", "Form the Roman numeral IV", "Stack in a 4 shape", "Spell the word FOUR"]'::jsonb, 1, 'I and V shapes.'),
  ('funbrain', 'puzzles', '{"text": "Slice a cylinder lengthwise and unroll the curved surface. What 2D shape?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A rectangle", "A parallelogram", "A circle", "An ellipse"]'::jsonb, 0, 'Height × circumference.'),
  ('funbrain', 'puzzles', '{"text": "Minimum straight lines through all 9 dots in 3×3 without lifting pen?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["4 lines", "6 lines", "3 lines", "5 lines"]'::jsonb, 0, 'Extend lines outside the dot square.'),
  ('funbrain', 'puzzles', '{"text": "3×3×3 cube painted red outside. How many small cubes have exactly 3 painted faces?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["12", "1", "8 cubes", "6"]'::jsonb, 2, 'Corner cubes only; a cube has 8 corners.'),
  ('funbrain', 'puzzles', '{"text": "Sum of interior angles of any plane triangle?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["270 degrees", "90 degrees", "180 degrees", "360 degrees"]'::jsonb, 2, 'Euclidean geometry.'),
  ('funbrain', 'puzzles', '{"text": "How many equal sides does a regular hexagon have?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["8", "12", "6 sides", "5"]'::jsonb, 2, 'Hex = six.'),
  ('funbrain', 'puzzles', '{"text": "Square cut corner to corner. What two shapes?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["Two rectangles", "Two right-angled triangles", "Two squares", "Two trapezoids"]'::jsonb, 1, 'Diagonal bisects square.'),
  ('funbrain', 'puzzles', '{"text": "No angles but not a circle or oval — in 3D?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A point", "A torus", "A line", "A sphere"]'::jsonb, 3, 'Smooth closed surface, no vertices.'),
  ('funbrain', 'puzzles', '{"text": "How many parallel lines in a perfect circle?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["One", "Two", "Zero", "Infinite"]'::jsonb, 2, 'No straight lines on a circle.'),
  ('funbrain', 'puzzles', '{"text": "Six faces, twenty-one eyes, cannot see?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["A bee", "A standard playing die (dice)", "A house", "A robot"]'::jsonb, 1, 'Six faces; pips total 1+…+6 = 21.'),
  ('funbrain', 'puzzles', '{"text": "If 1=3, 2=3, 3=5, 4=4, 5=4 by counting letters, what is 6=?", "pack": "cbse_puzzles_puc100_basic"}'::jsonb, '["5", "3", "4", "6"]'::jsonb, 1, 'S-I-X has three letters.'),
